using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // --- CalculateTotal: DataRow for inline combinations ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(25.00, 2, 0.10, 55.00, DisplayName = "Two items, 10% tax")]
    [DataRow(100.00, 3, 0.20, 360.00, DisplayName = "Three items, 20% tax")]
    [DataRow(0.00, 10, 0.15, 0.00, DisplayName = "Zero price")]
    [DataRow(9.99, 0, 0.05, 0.00, DisplayName = "Zero quantity")]
    [DataRow(49.99, 1, 1.0, 99.98, DisplayName = "100% tax")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, "unitPrice", DisplayName = "Negative price throws")]
    [DataRow(10.00, -1, 0.10, "quantity", DisplayName = "Negative quantity throws")]
    [DataRow(10.00, 1, -0.01, "taxRate", DisplayName = "Negative tax rate throws")]
    [DataRow(10.00, 1, 1.01, "taxRate", DisplayName = "Tax rate > 1 throws")]
    public void CalculateTotal_WithInvalidInputs_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate, string expectedParam)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual(expectedParam, ex.ParamName);
    }

    // --- ApplyDiscount: DynamicData with ValueTuples for type-safe complex data ---

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountTestData))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> ApplyDiscountTestData =>
    [
        (100m, 10m, 90m),
        (200m, 25m, 150m),
        (50m, 0m, 50m),
        (80m, 100m, 0m),
        (99.99m, 50m, 49.995m),
        (0m, 15m, 0m),
    ];

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Discount below 0 throws")]
    [DataRow(100.1, DisplayName = "Discount above 100 throws")]
    public void ApplyDiscount_WithInvalidPercent_ThrowsArgumentOutOfRange(double discount)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discount));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }

    // --- FormatPrice: DataRow for string outputs ---

    [TestMethod]
    [DataRow(19.99, "$", "$19.99", DisplayName = "Default dollar symbol")]
    [DataRow(5.5, "€", "€5.50", DisplayName = "Euro with rounding")]
    [DataRow(0.0, "£", "£0.00", DisplayName = "Zero in pounds")]
    [DataRow(1234.567, "$", "$1234.57", DisplayName = "Rounds to 2 decimals")]
    public void FormatPrice_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }
}

